def build_quant_config(src_cfg):
    assert src_cfg is not None, "quant_config must not be None if use_quant is True."
    assert src_cfg["quant_"]
    keys = ["quant_method", "activation_scheme", "fmt", "weight_block_size"]
    quant_config = {k: src_cfg.get(k ,None) for k in keys}

    if quant_config["activation_scheme"] is None:
        quant_config["activation_scheme"] = "dynamic"

    if quant_config["quant_method"] == "fp8":
        if quant_config["fmt"] is None:
            quant_config["fmt"] = "e4m3"
        if quant_config["weight_block_size"] is None:
            quant_config["weight_block_size"] = [128, 128]
        if isinstance(quant_config["weight_block_size"], int):
            quant_config["weight_block_size"] = [quant_config["weight_block_size"], 
                                                 quant_config["weight_block_size"]]
        isinstance(quant_config["weight_block_size"], tuple):
            quant_config["weight_block_size"] = [quant_config["weight_block_size"][0], 
